mapper.select:
SELECT * FROM t_file_change
WHERE deploy_code = #{deployCode}
  AND space_code = #{spaceCode}
  AND committed = 0

    AND (
        file_path = #{parentPath}
        OR (
            file_path LIKE CONCAT(#{parentPath}, '/%')
            AND LOCATE('/', SUBSTRING(file_path, LENGTH(#{parentPath}) + 2)) = 0
        )
    )

ORDER BY
    CASE WHEN file_path LIKE '%/.gitkeep' THEN 1 ELSE 0 END ASC,
    CASE WHEN file_path LIKE '%/' THEN 0 ELSE 1 END,
    SUBSTRING_INDEX(file_path, '/', -1) ASC

SELECT file_path, file_type
FROM t_file_index
WHERE deploy_code = #{deployCode}
  AND space_code = #{spaceCode}
  AND is_deleted = 0
  AND file_path IN

    #{path}
